import streamlit as st
import pandas as pd
import plotly.graph_objects as go
import warnings
warnings.filterwarnings('ignore')

st.set_page_config(
    page_title="تحليل حوادث المرور - KSA",
    page_icon="🚦",
    layout="wide",
    initial_sidebar_state="expanded"
)

# CSS
st.markdown("""
<style>
    .main {background: linear-gradient(135deg, #1e3c72 0%, #2a5298 100%);}
    .metric-card {
        background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
        padding: 25px; border-radius: 15px; box-shadow: 0 8px 16px rgba(0,0,0,0.2);
        text-align: center; color: white; margin: 10px 0;
    }
    .metric-card h3 {font-size: 18px; margin-bottom: 10px; opacity: 0.9;}
    .metric-card h1 {font-size: 42px; margin: 10px 0; font-weight: 700;}
    .main-header {
        background: linear-gradient(90deg, #1e3c72 0%, #2a5298 100%);
        padding: 30px; border-radius: 20px; text-align: center; color: white;
        margin-bottom: 30px; box-shadow: 0 10px 30px rgba(0,0,0,0.3);
    }
    .section-header {
        background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
        padding: 20px; border-radius: 10px; color: white;
        margin: 30px 0 20px 0; box-shadow: 0 5px 15px rgba(0,0,0,0.2);
    }
    [data-testid="stSidebar"] {background: linear-gradient(180deg, #1e3c72 0%, #2a5298 100%);}
    [data-testid="stSidebar"] * {color: white !important;}
    #MainMenu, footer, header {visibility: hidden;}
    .info-box {background: white; padding: 20px; border-radius: 10px; margin: 15px 0;}
</style>
""", unsafe_allow_html=True)

@st.cache_data
def load_data():
    df = pd.DataFrame(TRAFFIC_DATA)
    return df

df = load_data()

st.markdown("""
<div class="main-header">
    <h1>🚦 تحليل حوادث المرور في المملكة العربية السعودية</h1>
    <p>الإدارة العامة للمرور - وزارة الداخلية | ١٤٣٧-١٤٣٩ هـ | البيانات الحقيقية</p>
</div>
""", unsafe_allow_html=True)

# الشريط الجانبي
st.sidebar.markdown("## 🎛️ لوحة التحكم")
selected_years = st.sidebar.multiselect(
    "السنة (هـ)", sorted(df['year'].unique()), sorted(df['year'].unique())
)
selected_cities = st.sidebar.multiselect(
    "المدينة", sorted(df['city'].unique()), sorted(df['city'].unique())[:10]
)
selected_months = st.sidebar.slider("نطاق الأشهر", 1, 12, (1, 12))

st.sidebar.markdown(f"""
<div style='background: rgba(255,255,255,0.1); padding: 15px; border-radius: 10px;'>
    <h4>📊 البيانات الحقيقية</h4>
    <p style='font-size: 14px;'>المدن: {len(df['city'].unique())}</p>
    <p style='font-size: 14px;'>السجلات: {len(df):,}</p>
</div>
""", unsafe_allow_html=True)

filtered_df = df[
    (df['year'].isin(selected_years)) &
    (df['city'].isin(selected_cities)) &
    (df['month'] >= selected_months[0]) &
    (df['month'] <= selected_months[1])
]

if len(filtered_df) == 0:
    st.warning("⚠️ لا توجد بيانات")
    st.stop()

# المقاييس
total_injured = int(filtered_df['male'].sum() + filtered_df['female'].sum())
male_injured = int(filtered_df['male'].sum())
female_injured = int(filtered_df['female'].sum())
male_pct = (male_injured / total_injured * 100) if total_injured > 0 else 0

col1, col2, col3, col4 = st.columns(4)
with col1:
    st.markdown(f'<div class="metric-card"><h3>إجمالي المصابين</h3><h1>{total_injured:,}</h1></div>', unsafe_allow_html=True)
with col2:
    st.markdown(f'<div class="metric-card"><h3>ذكور</h3><h1>{male_injured:,}</h1><p>{male_pct:.1f}%</p></div>', unsafe_allow_html=True)
with col3:
    st.markdown(f'<div class="metric-card"><h3>إناث</h3><h1>{female_injured:,}</h1><p>{100-male_pct:.1f}%</p></div>', unsafe_allow_html=True)
with col4:
    avg = total_injured / len(filtered_df) if len(filtered_df) > 0 else 0
    st.markdown(f'<div class="metric-card"><h3>متوسط شهري</h3><h1>{avg:.0f}</h1></div>', unsafe_allow_html=True)

# الاتجاه الزمني
st.markdown('<div class="section-header"><h2>📈 الاتجاه الزمني</h2></div>', unsafe_allow_html=True)
col1, col2 = st.columns(2)

with col1:
    yearly = filtered_df.groupby('year')[['male', 'female']].sum()
    yearly['total'] = yearly['male'] + yearly['female']
    
    fig1 = go.Figure(go.Bar(
        x=yearly.index, y=yearly['total'], marker_color='#667eea',
        text=yearly['total'], textposition='outside', texttemplate='%{text:,.0f}'
    ))
    fig1.update_layout(
        title='المصابين حسب السنة', template='plotly_dark', height=400, showlegend=False
    )
    st.plotly_chart(fig1, use_container_width=True)
    
    if len(yearly) > 1:
        change = ((yearly.iloc[-1]['total'] - yearly.iloc[0]['total']) / yearly.iloc[0]['total'] * 100)
        color = 'green' if change < 0 else 'red'
        symbol = '↓' if change < 0 else '↑'
        st.markdown(f"""
        <div style='background: white; padding: 15px; border-radius: 10px; text-align: center;'>
            <p style='color: {color}; font-size: 20px; font-weight: bold; margin: 0;'>
                {symbol} {abs(change):.1f}%
            </p>
        </div>
        """, unsafe_allow_html=True)

with col2:
    monthly = filtered_df.groupby(['year', 'month'])[['male', 'female']].sum()
    monthly['total'] = monthly['male'] + monthly['female']
    monthly = monthly.reset_index()
    
    fig2 = go.Figure()
    colors = {1437: '#2980B9', 1438: '#1ABC9C', 1439: '#8E44AD'}
    
    for year in sorted(monthly['year'].unique()):
        data = monthly[monthly['year'] == year]
        fig2.add_trace(go.Scatter(
            x=data['month'], y=data['total'], name=f'{year} هـ',
            mode='lines+markers', line=dict(width=3, color=colors.get(year)), marker=dict(size=8)
        ))
    
    fig2.add_vrect(x0=8.5, x1=9.5, fillcolor="orange", opacity=0.2, 
                   annotation_text="رمضان", annotation_position="top")
    fig2.update_layout(
        title='الاتجاه الشهري', template='plotly_dark', height=400, hovermode='x unified'
    )
    st.plotly_chart(fig2, use_container_width=True)

# التوزيع الجغرافي
st.markdown('<div class="section-header"><h2>🗺️ التوزيع الجغرافي</h2></div>', unsafe_allow_html=True)
col1, col2 = st.columns(2)

with col1:
    city_data = filtered_df.groupby('city')[['male', 'female']].sum()
    city_data['total'] = city_data['male'] + city_data['female']
    city_data = city_data.sort_values('total', ascending=True).tail(12)
    
    fig3 = go.Figure(go.Bar(
        y=city_data.index, x=city_data['total'], orientation='h',
        marker=dict(color=city_data['total'], colorscale='Reds', showscale=True),
        text=city_data['total'], textposition='outside', texttemplate='%{text:,.0f}'
    ))
    fig3.update_layout(title='أعلى 12 مدينة', template='plotly_dark', height=500)
    st.plotly_chart(fig3, use_container_width=True)

with col2:
    fig4 = go.Figure()
    fig4.add_trace(go.Bar(y=city_data.index, x=city_data['male'], name='ذكور', 
                          orientation='h', marker_color='#3498db'))
    fig4.add_trace(go.Bar(y=city_data.index, x=city_data['female'], name='إناث', 
                          orientation='h', marker_color='#e74c3c'))
    fig4.update_layout(title='توزيع حسب الجنس', template='plotly_dark', 
                       height=500, barmode='stack')
    st.plotly_chart(fig4, use_container_width=True)

# التحليل الديموغرافي
st.markdown('<div class="section-header"><h2>👥 التحليل الديموغرافي</h2></div>', unsafe_allow_html=True)
col1, col2, col3 = st.columns(3)

with col1:
    fig5 = go.Figure(go.Pie(
        labels=['ذكور', 'إناث'], values=[male_injured, female_injured], hole=0.4,
        marker=dict(colors=['#3498db', '#e74c3c'])
    ))
    fig5.update_layout(title='الجنس', template='plotly_dark', height=350)
    st.plotly_chart(fig5, use_container_width=True)

with col2:
    fig6 = go.Figure(go.Pie(
        labels=['داخل', 'خارج'], 
        values=[filtered_df['inside_city'].sum(), filtered_df['outside_city'].sum()],
        hole=0.4, marker=dict(colors=['#16a085', '#d35400'])
    ))
    fig6.update_layout(title='الموقع', template='plotly_dark', height=350)
    st.plotly_chart(fig6, use_container_width=True)

with col3:
    fig7 = go.Figure(go.Pie(
        labels=['سعودي', 'غير سعودي'],
        values=[filtered_df['saudi'].sum(), filtered_df['non_saudi'].sum()],
        hole=0.4, marker=dict(colors=['#27ae60', '#c0392b'])
    ))
    fig7.update_layout(title='الجنسية', template='plotly_dark', height=350)
    st.plotly_chart(fig7, use_container_width=True)

# الاستنتاجات
st.markdown('<div class="section-header"><h2>💡 الاستنتاجات</h2></div>', unsafe_allow_html=True)
col1, col2 = st.columns(2)

total_1437 = df[df['year']==1437][['male','female']].sum().sum()
total_1439 = df[df['year']==1439][['male','female']].sum().sum()
decrease = ((total_1437 - total_1439) / total_1437 * 100)

with col1:
    st.markdown(f"""
    <div class="info-box">
        <h3 style='color: #2c3e50;'>📊 الاستنتاجات:</h3>
        <ul style='color: #34495e; line-height: 1.8;'>
            <li><strong>انخفاض:</strong> {decrease:.1f}% ({total_1437:,.0f} → {total_1439:,.0f})</li>
            <li><strong>الذكور:</strong> {male_pct:.1f}% من المصابين</li>
            <li><strong>16 مدينة</strong> في التحليل</li>
        </ul>
    </div>
    """, unsafe_allow_html=True)

with col2:
    st.markdown("""
    <div class="info-box">
        <h3 style='color: #2c3e50;'>🎯 التوصيات:</h3>
        <ul style='color: #34495e; line-height: 1.8;'>
            <li>تكثيف الحملات في رمضان</li>
            <li>تحسين الأمن خارج المدن</li>
            <li>برامج توعية مستهدفة</li>
        </ul>
    </div>
    """, unsafe_allow_html=True)

# البيانات التفصيلية
st.markdown('<div class="section-header"><h2>📋 البيانات التفصيلية</h2></div>', unsafe_allow_html=True)

display_df = filtered_df.groupby(['year', 'city']).agg({
    'male': 'sum', 'female': 'sum', 'inside_city': 'sum', 'outside_city': 'sum'
}).reset_index()
display_df['total'] = display_df['male'] + display_df['female']
display_df = display_df.sort_values('total', ascending=False)
display_df.columns = ['السنة', 'المدينة', 'ذكور', 'إناث', 'داخل', 'خارج', 'الإجمالي']

st.dataframe(
    display_df.style.background_gradient(cmap='RdYlGn_r', subset=['الإجمالي']),
    use_container_width=True, height=400
)

